<span class="line">                <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token namespace">w:</span>rFonts</span> <span class="token attr-name"><span class="token namespace">w:</span>ascii</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>华文楷体<span class="token punctuation">&quot;</span></span> <span class="token attr-name"><span class="token namespace">w:</span>eastAsia</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>华文楷体<span class="token punctuation">&quot;</span></span> <span class="token attr-name"><span class="token namespace">w:</span>hAnsi</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>华文楷体<span class="token punctuation">&quot;</span></span><span class="token punctuation">/&gt;</span></span></span>
